#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <sstream>
#include <chrono>
#include <cstdio>

// Logger class definition will be inserted here by the system

std::string run_test(const std::vector<std::string>& messages, const std::string& filename) {
    std::ofstream clear_file(filename, std::ios::trunc);
    clear_file.close();

    Logger logger(filename);

    for (const std::string& msg : messages) {
        logger.logMessage(msg);
    }

    std::ifstream infile(filename);
    std::stringstream buffer;
    if (infile.is_open()) {
        buffer << infile.rdbuf();
        infile.close();
    } else {
        return "ERROR: Could not read log file: " + filename + "\n";
    }
    return buffer.str();
}

int main() {
    std::vector<std::string> test_messages_1 = {"Application started successfully.", "Configuration loaded from config.ini", "Performing initial data sync... Done."};
    std::string temp_log_filename_1 = "temp_log_" + std::to_string(std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::system_clock::now().time_since_epoch()).count()) + "_1.txt";
    std::cout << run_test(test_messages_1, temp_log_filename_1);
    std::remove(temp_log_filename_1.c_str());

    std::vector<std::string> test_messages_2 = {"User 'admin' accessed critical resource.", "Audit log: Operation 'delete' on item 'XYZ'.", "Security alert cleared."};
    std::string temp_log_filename_2 = "temp_log_" + std::to_string(std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::system_clock::now().time_since_epoch()).count()) + "_2.txt";
    std::cout << run_test(test_messages_2, temp_log_filename_2);
    std::remove(temp_log_filename_2.c_str());

    return 0;
}
